import { useEffect, useRef, useState, useCallback } from 'react';
import { io, Socket } from 'socket.io-client';
import { Message, Partner, AdminUser, AdminBan, Identity } from '../types';

const SERVER_URL =
  import.meta.env.VITE_BACKEND_URL ||
  "http://localhost:5000";

console.log("Connecting to:", SERVER_URL);

export function useSocket() {
  const socketRef = useRef<Socket | null>(null);
  const [connected, setConnected] = useState<boolean>(false);
  const [identity, setIdentity] = useState<Identity | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [soulCount, setSoulCount] = useState<number>(0);
  const [typingUsers, setTypingUsers] = useState<Record<string, { name: string; avatar: string }>>({});

  // Rooms
  const [currentRoom, setCurrentRoom] = useState<string>('lobby');

  // Matchmaking
  const [matchStatus, setMatchStatus] = useState<'idle' | 'searching' | 'paired'>('idle');
  const [partner, setPartner] = useState<Partner | null>(null);

  // Voice Chat
  const [isVoiceActive, setIsVoiceActive] = useState<boolean>(false);
  const [isPartnerVoiceActive, setIsPartnerVoiceActive] = useState<boolean>(false);
  const [localStream, setLocalStream] = useState<MediaStream | null>(null);
  const [remoteStream, setRemoteStream] = useState<MediaStream | null>(null);

  // Admin
  const [isAdmin, setIsAdmin] = useState<boolean>(false);
  const [adminUsers, setAdminUsers] = useState<AdminUser[]>([]);
  const [adminBans, setAdminBans] = useState<AdminBan[]>([]);
  const [adminError, setAdminError] = useState<string | null>(null);

  // Bans
  const [isBanned, setIsBanned] = useState<boolean>(false);
  const [banReason, setBanReason] = useState<string>('');

  // Refs for WebRTC
  const pcRef = useRef<RTCPeerConnection | null>(null);
  const localStreamRef = useRef<MediaStream | null>(null);

  // Retrieve or generate persistent deviceId
  const deviceId = useRef<string>('');
  if (!deviceId.current) {
    let id = localStorage.getItem('void_device_id');
    if (!id) {
      id = 'void_dev_' + Math.random().toString(36).substring(2, 9) + '_' + Date.now();
      localStorage.setItem('void_device_id', id);
    }
    deviceId.current = id;
  }

  // Clean WebRTC Connection helper
  const closePeerConnection = useCallback(() => {
    if (pcRef.current) {
      pcRef.current.close();
      pcRef.current = null;
    }
    if (localStreamRef.current) {
      localStreamRef.current.getTracks().forEach((track) => track.stop());
      localStreamRef.current = null;
      setLocalStream(null);
    }
    setRemoteStream(null);
    setIsVoiceActive(false);
    setIsPartnerVoiceActive(false);
  }, []);

  useEffect(() => {
    const socket = io(SERVER_URL, {
      transports: ['websocket', 'polling'],
      reconnectionAttempts: 10,
      reconnectionDelay: 1500,
      query: { deviceId: deviceId.current }
    });
    socketRef.current = socket;

    socket.on('connect', () => setConnected(true));
    socket.on('disconnect', () => {
      setConnected(false);
      closePeerConnection();
    });
    socket.on('connect_error', () => setConnected(false));

    socket.on('your-identity', (data: Identity) => {
      setIdentity(data);
    });

    socket.on('history', (msgs: Message[]) => {
      setMessages(msgs);
    });

    socket.on('receive-message', (msg: Message) => {
      setMessages((prev) => [...prev, msg]);
    });

    socket.on('system-message', (msg: Message) => {
      setMessages((prev) => [...prev, { ...msg, isSystem: true }]);
    });

    socket.on('soul-count', (count: number) => {
      setSoulCount(count);
    });

    socket.on('user-typing', ({ id, name, avatar }: { id: string; name: string; avatar: string }) => {
      setTypingUsers((prev) => ({ ...prev, [id]: { name, avatar } }));
    });

    socket.on('user-stopped-typing', (id: string) => {
      setTypingUsers((prev) => {
        const next = { ...prev };
        delete next[id];
        return next;
      });
    });

    socket.on('rate-limited', ({ message }: { message: string }) => {
      setMessages((prev) => [
        ...prev,
        { id: 'rl_' + Date.now(), room: '', authorId: 'system', avatar: '☠', name: 'VOID', text: message, imageUrl: null, reactions: {}, ts: Date.now(), isSystem: true },
      ]);
    });

    socket.on('report-received', ({ message }: { message: string }) => {
      setMessages((prev) => [
        ...prev,
        { id: 'rep_' + Date.now(), room: '', authorId: 'system', avatar: '☠', name: 'VOID', text: message, imageUrl: null, reactions: {}, ts: Date.now(), isSystem: true },
      ]);
    });

    socket.on('message-reaction-updated', ({ messageId, reactions }: { messageId: string; reactions: Record<string, string[]> }) => {
      setMessages((prev) =>
        prev.map((msg) => (msg.id === messageId ? { ...msg, reactions } : msg))
      );
    });

    socket.on('matchmaking-status', (status: 'searching' | 'idle') => {
      if (status === 'searching') {
        setMatchStatus('searching');
        setPartner(null);
        setMessages([]);
      } else if (status === 'idle') {
        setMatchStatus('idle');
        setPartner(null);
      }
    });

    socket.on('match-paired', ({ partner: partnerData }: { partner: Partner }) => {
      setMatchStatus('paired');
      setPartner(partnerData);
      setMessages([]);
      closePeerConnection();
    });

    socket.on('match-unpaired', ({ reason }: { reason: string }) => {
      setMatchStatus('idle');
      setPartner(null);
      closePeerConnection();
      let text = 'Connection lost in the dark.';
      if (reason === 'partner_skipped') {
        text = 'Your partner has vanished. Searching for a new soul...';
      } else if (reason === 'partner_disconnected') {
        text = 'Your partner has disconnected. Searching for a new soul...';
      }
      setMessages((prev) => [
        ...prev,
        { id: 'unpaired_' + Date.now(), room: '', authorId: 'system', avatar: '☠', name: 'VOID', text, imageUrl: null, reactions: {}, ts: Date.now(), isSystem: true },
      ]);
    });

    socket.on('webrtc-offer', async ({ sdp }: { sdp: RTCSessionDescriptionInit }) => {
      try {
        if (!pcRef.current) {
          initiatePeerConnection();
        }
        if (pcRef.current) {
          await pcRef.current.setRemoteDescription(new RTCSessionDescription(sdp));
          const answer = await pcRef.current.createAnswer();
          await pcRef.current.setLocalDescription(answer);
          socketRef.current?.emit('webrtc-answer', { sdp: answer });
        }
      } catch (err) {
        console.error("Error handling WebRTC offer:", err);
      }
    });

    socket.on('webrtc-answer', async ({ sdp }: { sdp: RTCSessionDescriptionInit }) => {
      try {
        if (pcRef.current) {
          await pcRef.current.setRemoteDescription(new RTCSessionDescription(sdp));
        }
      } catch (err) {
        console.error("Error handling WebRTC answer:", err);
      }
    });

    socket.on('webrtc-ice-candidate', async ({ candidate }: { candidate: RTCIceCandidateInit }) => {
      try {
        if (pcRef.current) {
          await pcRef.current.addIceCandidate(new RTCIceCandidate(candidate));
        }
      } catch (err) {
        console.error("Error adding ICE candidate:", err);
      }
    });

    socket.on('voice-state', ({ enabled }: { enabled: boolean }) => {
      setIsPartnerVoiceActive(enabled);
    });

    socket.on('admin-auth-success', () => {
      setIsAdmin(true);
      setAdminError(null);
    });

    socket.on('admin-auth-fail', ({ message }: { message: string }) => {
      setIsAdmin(false);
      setAdminError(message);
    });

    socket.on('admin-users-list', (list: AdminUser[]) => {
      setAdminUsers(list);
    });

    socket.on('admin-bans-list', (list: AdminBan[]) => {
      setAdminBans(list);
    });

    socket.on('banned', ({ reason }: { reason: string }) => {
      setIsBanned(true);
      setBanReason(reason);
      closePeerConnection();
      socket.disconnect();
    });

    return () => {
      closePeerConnection();
      socket.disconnect();
    };
  }, [closePeerConnection]);

  const initiatePeerConnection = () => {
    if (pcRef.current) return;

    const pc = new RTCPeerConnection({
      iceServers: [
        { urls: 'stun:stun.l.google.com:19302' },
        { urls: 'stun:stun1.l.google.com:19302' },
      ],
    });

    pc.onicecandidate = (event) => {
      if (event.candidate) {
        socketRef.current?.emit('webrtc-ice-candidate', { candidate: event.candidate });
      }
    };

    pc.ontrack = (event) => {
      if (event.streams && event.streams[0]) {
        setRemoteStream(event.streams[0]);
      }
    };

    if (localStreamRef.current) {
      localStreamRef.current.getTracks().forEach((track) => {
        if (localStreamRef.current) {
          pc.addTrack(track, localStreamRef.current);
        }
      });
    }

    pcRef.current = pc;
  };

  const toggleVoice = async () => {
    if (isVoiceActive) {
      if (localStreamRef.current) {
        localStreamRef.current.getTracks().forEach((track) => track.stop());
        localStreamRef.current = null;
        setLocalStream(null);
      }
      setIsVoiceActive(false);
      socketRef.current?.emit('voice-state', { enabled: false });

      if (pcRef.current) {
        pcRef.current.close();
        pcRef.current = null;
      }
      setRemoteStream(null);
    } else {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
        localStreamRef.current = stream;
        setLocalStream(stream);
        setIsVoiceActive(true);
        socketRef.current?.emit('voice-state', { enabled: true });

        if (isPartnerVoiceActive) {
          initiateCall();
        }
      } catch (err) {
        console.error("Failed to access microphone:", err);
        alert("Microphone access is required for voice chat.");
      }
    }
  };

  useEffect(() => {
    if (isVoiceActive && isPartnerVoiceActive && !pcRef.current && identity && partner) {
      const isInitiator = identity.name < partner.name;
      if (isInitiator) {
        initiateCall();
      }
    }
  }, [isVoiceActive, isPartnerVoiceActive, identity, partner]);

  const initiateCall = async () => {
    try {
      initiatePeerConnection();
      if (pcRef.current) {
        const offer = await pcRef.current.createOffer();
        await pcRef.current.setLocalDescription(offer);
        socketRef.current?.emit('webrtc-offer', { sdp: offer });
      }
    } catch (err) {
      console.error("Error creating WebRTC offer:", err);
    }
  };

  const sendMessage = useCallback((text: string, imageUrl: string | null = null) => {
    socketRef.current?.emit('send-message', { text, imageUrl });
  }, []);

  const reactToMessage = useCallback((messageId: string, reactionType: string) => {
    socketRef.current?.emit('react-message', { messageId, reactionType });
  }, []);

  const sendTypingStart = useCallback(() => {
    socketRef.current?.emit('typing-start');
  }, []);

  const sendTypingStop = useCallback(() => {
    socketRef.current?.emit('typing-stop');
  }, []);

  const reportMessage = useCallback((messageId: string) => {
    socketRef.current?.emit('report-message', { messageId });
  }, []);

  const switchRoom = useCallback((roomName: string) => {
    if (matchStatus === 'paired') return;
    setCurrentRoom(roomName);
    setMessages([]);
    socketRef.current?.emit('switch-room', roomName);
  }, [matchStatus]);

  const joinMatchmaking = useCallback(() => {
    socketRef.current?.emit('join-matchmaking');
  }, []);

  const leaveMatchmaking = useCallback(() => {
    socketRef.current?.emit('leave-matchmaking');
  }, []);

  const skipMatch = useCallback(() => {
    socketRef.current?.emit('skip-match');
  }, []);

  const authenticateAdmin = useCallback((token: string) => {
    socketRef.current?.emit('admin-auth', { token });
  }, []);

  const banUser = useCallback((socketId: string, deviceId: string, ipAddress: string, reason: string) => {
    socketRef.current?.emit('admin-ban-user', { socketId, deviceId, ipAddress, reason });
  }, []);

  const unbanUser = useCallback((ipOrDeviceId: string) => {
    socketRef.current?.emit('admin-unban', { ipOrDeviceId });
  }, []);

  const getBans = useCallback(() => {
    socketRef.current?.emit('admin-get-bans');
  }, []);

  const socketId = socketRef.current?.id;

  return {
    connected,
    identity,
    messages,
    soulCount,
    typingUsers,
    sendMessage,
    reactToMessage,
    sendTypingStart,
    sendTypingStop,
    reportMessage,
    socketId,

    // Rooms
    currentRoom,
    switchRoom,

    // Matchmaking
    matchStatus,
    partner,
    joinMatchmaking,
    leaveMatchmaking,
    skipMatch,

    // Voice Chat
    isVoiceActive,
    isPartnerVoiceActive,
    toggleVoice,
    remoteStream,

    // Admin
    isAdmin,
    adminUsers,
    adminBans,
    adminError,
    authenticateAdmin,
    banUser,
    unbanUser,
    getBans,

    // Bans
    isBanned,
    banReason
  };
}
